        <span className="pointer-events-none absolute inset-0 grid place-items-center rounded-full">
          <Spinner className="size-4" />
        </span>
      )}
      <Slot.Slottable>{children}</Slot.Slottable>
    </Comp>
  );
};

export { Button, buttonVariants };

